class Solution:
    def largestPalindrome(self, n):
        # Naive: scan every pair of n-digit factors from the top, keep the
        # largest product that reads as a palindrome. Pruned by the best found
        # so far; deliberately independent of the half-construction approach.
        if n == 1:
            return 9
        upper = 10 ** n - 1
        lower = 10 ** (n - 1)
        best = -1
        for i in range(upper, lower - 1, -1):
            if i * upper <= best:
                break
            for j in range(i, lower - 1, -1):
                p = i * j
                if p <= best:
                    break
                s = str(p)
                if s == s[::-1]:
                    best = p
        return best % 1337 if best >= 0 else -1

