var largestPalindrome = function(n) {
    if (n === 1) return 9;
    const upper = 10 ** n - 1;
    const lower = 10 ** (n - 1);
    for (let half = upper; half >= lower; half--) {
        const s = String(half);
        const pal = BigInt(s + s.split('').reverse().join(''));
        for (let d = BigInt(upper); d * d >= pal; d--) {
            if (pal % d === 0n) {
                const co = pal / d;
                if (co >= BigInt(lower) && co <= BigInt(upper)) {
                    return Number(pal % 1337n);
                }
            }
        }
    }
    return -1;
};
